const input = $input.first().json;
const payload = input.body ?? input.payload ?? input;
const appSignature = input.headers?.['x-app-signature'] ?? null;

return [{
  json: {
    ...input,
    payload,
    app_signature: appSignature,
    job_id: input.job_id ?? payload.job_id ?? payload?.job?.id,
    project_id: input.project_id ?? payload.project_id ?? payload?.project?.id,
    user_id: input.user_id ?? payload.user_id ?? payload?.user?.id,
    diagnosis_id: input.diagnosis_id ?? payload.diagnosis_id ?? payload?.diagnosis?.id,
    identify_drafts: input.identify_drafts ?? payload.identify_drafts ?? payload?.identify?.drafts ?? [],
    identify_merged: input.identify_merged ?? payload.identify_merged ?? payload?.identify?.merged ?? {}
  }
}];

const input = $input.first().json;
const rawBody = JSON.stringify(input.body ?? input.payload ?? input);

const expected = await (async () => {
  const encoder = new TextEncoder();
  const secret = $env.N8N_WEBHOOK_SECRET;
  const key = await globalThis.crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const signatureBuffer = await globalThis.crypto.subtle.sign('HMAC', key, encoder.encode(rawBody));
  return Array.from(new Uint8Array(signatureBuffer))
    .map((byte) => byte.toString(16).padStart(2, '0'))
    .join('');
})();

if (expected !== input.app_signature) {
  throw new Error('Invalid app signature');
}

return [{
  json: {
    ...input,
    verified: true
  }
}];

const raw = typeof query === 'string' ? query : JSON.stringify(query ?? {});
let parsed;
try {
  parsed = JSON.parse(raw);
} catch {
  parsed = { raw };
}

return JSON.stringify({
  reminder: 'Analyze intent match, crawlability, content depth, and internal links.',
  focus: parsed.main_seo_concern ?? null,
  trend: parsed.organic_traffic_trend ?? null,
  stage: parsed.website_stage ?? null,
  indexed_by_google: parsed.indexed_by_google ?? null
});

const input = $input.first().json;
const rawOutput = input.output ?? input.text ?? input.response ?? input.result ?? input;

let parsed = rawOutput;
if (typeof rawOutput === 'string') {
  try {
    parsed = JSON.parse(rawOutput);
  } catch {
    parsed = null;
  }
}

if (!parsed || typeof parsed !== 'object') {
  parsed = {
    primary_problem_type: 'unknown',
    secondary_problem_type: null,
    severity: 'medium',
    confidence_score: 50,
    diagnosis_summary: typeof rawOutput === 'string' ? rawOutput : 'AI output could not be parsed.',
    root_cause: 'The AI response was not valid JSON.',
    evidence: [],
    business_impact: {
      summary: 'Review the AI output and rerun the workflow.',
      metrics: []
    },
    campaign_readiness: 'needs_review',
    recommended_next_step: 'Inspect the AI Agent output and regenerate the diagnosis.',
    objective_direction: 'unknown',
    not_recommended_actions: [],
    warnings: ['AI output was not valid JSON'],
    raw_llm_output: rawOutput,
    model_used: 'n8n-ai-agent'
  };
}

return [{
  json: {
    ...input,
    diagnosis_result: parsed
  }
}];

const input = $input.first().json;
const diagnosisResult = input.diagnosis_result ?? {};
const now = new Date().toISOString();

const supabaseDiagnosisPayload = {
  primary_problem_type: diagnosisResult.primary_problem_type,
  secondary_problem_type: diagnosisResult.secondary_problem_type ?? null,
  severity: diagnosisResult.severity,
  confidence_score: diagnosisResult.confidence_score,
  diagnosis_summary: diagnosisResult.diagnosis_summary,
  root_cause: diagnosisResult.root_cause,
  evidence: diagnosisResult.evidence ?? [],
  business_impact: diagnosisResult.business_impact ?? {},
  campaign_readiness: diagnosisResult.campaign_readiness,
  recommended_next_step: diagnosisResult.recommended_next_step,
  objective_direction: diagnosisResult.objective_direction,
  not_recommended_actions: diagnosisResult.not_recommended_actions ?? [],
  warnings: diagnosisResult.warnings ?? [],
  raw_llm_output: diagnosisResult.raw_llm_output ?? {},
  model_used: diagnosisResult.model_used,
  status: 'completed',
  completed_at: now
};

const supabaseJobPayload = {
  status: 'completed',
  response_payload: diagnosisResult,
  completed_at: now
};

const supabaseUsageEventPayload = {
  user_id: input.user_id,
  event_type: 'diagnosis_run',
  metadata: {
    jobId: input.job_id,
    projectId: input.project_id,
    diagnosisId: input.diagnosis_id,
    source: 'n8n-identify-workflow'
  }
};

return [{
  json: {
    ...input,
    supabase_diagnosis_payload: supabaseDiagnosisPayload,
    supabase_job_payload: supabaseJobPayload,
    supabase_usage_event_payload: supabaseUsageEventPayload
  }
}];

